import requests
import json

def send_graphql_query(url: str, query: str, variables: dict = None, headers: dict = None) -> dict:
    """
    Belirtilen URL'ye bir GraphQL sorgusu gönderir.

    Args:
        url (str): GraphQL API'nin endpoint URL'si.
        query (str): Gönderilecek GraphQL sorgu dizesi.
        variables (dict, optional): Sorguyla birlikte gönderilecek değişkenler. Varsayılan None.
        headers (dict, optional): İstekle birlikte gönderilecek HTTP başlıkları. Varsayılan None.

    Returns:
        dict: API'den gelen JSON yanıtının sözlük olarak karşılığı.
              Hata durumunda 'error' anahtarı içeren bir sözlük döner.
    """
    payload = {'query': query}
    if variables:
        payload['variables'] = variables

    if not headers:
        headers = {'Content-Type': 'application/json'}

    try:
        response = requests.post(url, json=payload, headers=headers)
        response.raise_for_status()  # HTTP hataları için istisna fırlatır (4xx veya 5xx)
        return response.json()
    except requests.exceptions.HTTPError as e:
        return {"error": f"HTTP Hatası: {e.response.status_code} - {e.response.text}"}
    except requests.exceptions.ConnectionError as e:
        return {"error": f"Bağlantı Hatası: {e}"}
    except requests.exceptions.Timeout as e:
        return {"error": f"Zaman Aşımı Hatası: {e}"}
    except requests.exceptions.RequestException as e:
        return {"error": f"İstek Hatası: {e}"}
    except json.JSONDecodeError:
        return {"error": "API'den geçerli bir JSON yanıtı alınamadı."}
